const biz         = $('Fetch Business Profile').first().json;
const productRows = $('Fetch Products').all().map(i => i.json).filter(r => r && r.display_name);
const webhook     = $('Store Webhook').first().json;
const query       = webhook.query || {};

const platform   = (Array.isArray(query.plt) ? query.plt[0] : (query.plt || 'telegram')).toLowerCase();
const chatId     = Array.isArray(query.cid) ? query.cid[0] : (query.cid || '');
const storeToken = biz.store_token || '';
const bizMode    = (biz.business_mode || 'product_only');
const isService  = bizMode === 'service_only';
const botUsername = biz.bot_username || (Array.isArray(query.bot) ? query.bot[0] : (query.bot || ''));
const waNumber    = (biz.wa_number   || query.wa  || '').replace(/\D/g, '');

if (!biz || !biz.business_id) {
  return [{ json: { html: '<!DOCTYPE html><html><head><meta charset="UTF-8"/><meta name="viewport" content="width=device-width,initial-scale=1.0"/><title>Not found</title><style>body{font-family:sans-serif;display:flex;align-items:center;justify-content:center;min-height:100vh;background:#F5F4F2}.c{background:#fff;border-radius:16px;padding:40px;text-align:center;max-width:400px;box-shadow:0 4px 16px rgba(0,0,0,.08)}h2{color:#F13A01}p{color:#6B6560;font-size:14px;line-height:1.7;margin-top:8px}</style></head><body><div class="c"><h2>Store not found</h2><p>This link may have expired or been removed.</p></div></body></html>' }}];
}

const bizName = (biz.business_name || 'Our Store').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const bizDesc = (biz.description || '').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const bizLoc  = (biz.location || '').replace(/</g,'&lt;').replace(/>/g,'&gt;');

const sendLabel  = isService ? 'Send enquiry' : 'Send to chat';
const trayLabel  = isService ? 'Your enquiry' : 'Your selection';

function fmtPrice(price, priceLabel) {
  if (priceLabel) return priceLabel.replace(/</g,'&lt;').replace(/>/g,'&gt;');
  if (price !== null && price !== undefined && price !== '') {
    return '\u20a6' + Number(price).toLocaleString('en-NG');
  }
  return null;
}

const productData = productRows.map((p, i) => ({
  i:          i,
  name:       (p.display_name || 'Product'),
  price:      (p.price !== null && p.price !== undefined && p.price !== '') ? Number(p.price) : null,
  priceLabel: p.price_label || null,
  available:  p.is_available !== false
}));
const productDataJson = JSON.stringify(productData);

function buildCard(p, i) {
  const name  = (p.display_name || 'Product').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  const price = fmtPrice(p.price, p.price_label);
  const avail = p.is_available !== false;

  let imgHtml = '';
  if (p.minio_url) {
    const safeUrl = p.minio_url.replace(/"/g, '&quot;');
    imgHtml = '<img src="' + safeUrl + '" alt="' + name + '" loading="lazy" onerror="this.style.display=\'none\'">';
  } else {
    imgHtml = '<div class="img-ph">&#128230;</div>';
  }

  let priceHtml = '';
  if (!avail) {
    priceHtml = '<span class="badge-oos">Out of stock</span>';
  } else if (price) {
    priceHtml = '<div class="price">' + price + '</div>';
  } else {
    priceHtml = '<div class="price-unknown">Price on request</div>';
  }

  const selBtn = avail
    ? '<button class="btn-select" id="sel-' + i + '" onclick="toggle(' + i + ')">Select</button>'
      + '<div class="qty-row" id="qty-' + i + '">'
      + '<button class="qty-btn" onclick="decQty(' + i + ')">&#8722;</button>'
      + '<span class="qty-val" id="qval-' + i + '">1</span>'
      + '<button class="qty-btn" onclick="incQty(' + i + ')">+</button>'
      + '</div>'
    : '';

  return '<div class="card" id="card-' + i + '">'
    + '<div class="card-img">' + imgHtml + '</div>'
    + '<div class="card-body">'
    + '<div class="card-name">' + name + '</div>'
    + priceHtml
    + selBtn
    + '</div></div>';
}

const cardsHtml = productRows.length
  ? productRows.map((p, i) => buildCard(p, i)).join('')
  : '<div class="empty"><div class="empty-icon">&#128717;</div><p>No products yet.</p></div>';

const descSnippet = bizLoc
  ? '<p>&#128205; ' + bizLoc + '</p>'
  : bizDesc
  ? '<p>' + bizDesc.substring(0, 55) + (bizDesc.length > 55 ? '&hellip;' : '') + '</p>'
  : '';

// ── Build HTML using string concatenation — no template literals ─────────────
// Browser JS is embedded as plain string concatenation lines
// to avoid any escaping issues with n8n's code node

const bizId    = biz.business_id || '';
const ENDPOINT = '[URL]';

const scriptLines = [
  'var PRODUCTS='   + productDataJson + ';',
  'var PLATFORM="'  + platform    + '";',
  'var CHAT_ID="'   + chatId      + '";',
  'var STORE_TOKEN="'+ storeToken  + '";',
  'var BIZ_ID="'    + bizId        + '";',
  'var BOT_USERNAME="'+ botUsername + '";',
  'var WA_NUMBER="' + waNumber     + '";',
  'var ENDPOINT="'  + ENDPOINT     + '";',
  'var state={};',
  'function fmt(p){return "\u20a6"+Number(p).toLocaleString("en-NG");}',
  'function toggle(i){var p=PRODUCTS[i];if(!p.available)return;var k=p.name;if(state[k]){delete state[k];}else{state[k]={qty:1,price:p.price,priceLabel:p.priceLabel};}renderCard(i);renderTray();}',
  'function incQty(i){var k=PRODUCTS[i].name;if(state[k]&&state[k].qty<20){state[k].qty++;renderCard(i);renderTray();}}',
  'function decQty(i){var k=PRODUCTS[i].name;if(!state[k])return;if(state[k].qty<=1){delete state[k];renderCard(i);renderTray();return;}state[k].qty--;renderCard(i);renderTray();}',
  'function renderCard(i){var p=PRODUCTS[i];var k=p.name;var sel=!!state[k];var card=document.getElementById("card-"+i);var btn=document.getElementById("sel-"+i);var qrow=document.getElementById("qty-"+i);var qval=document.getElementById("qval-"+i);if(!btn)return;card.classList.toggle("selected",sel);btn.classList.toggle("active",sel);btn.textContent=sel?"Selected":"Select";if(qrow)qrow.className="qty-row"+(sel?" visible":"");if(qval&&state[k])qval.textContent=state[k].qty;}',
  'function renderTray(){var keys=Object.keys(state);var tray=document.getElementById("tray");var sum=document.getElementById("traySummary");var btn=document.getElementById("btnSend");if(!keys.length){tray.className="tray";btn.disabled=true;return;}tray.className="tray visible";var parts=keys.map(function(k){var s=state[k];var pr=s.price!==null?(s.priceLabel||fmt(s.price)):"price TBC";return s.qty>1?s.qty+"x "+k+" ("+pr+")":k+" ("+pr+")";});sum.textContent=parts.join(" \u00b7 ");btn.disabled=false;}',
  'function numToWords(n){var w=["one","two","three","four","five","six","seven","eight","nine","ten","eleven","twelve","thirteen","fourteen","fifteen","sixteen","seventeen","eighteen","nineteen","twenty"];return(n>=1&&n<=20)?w[n-1]:String(n);}function buildMsg(){var keys=Object.keys(state);var orders=keys.filter(function(k){return state[k].price!==null;});var asks=keys.filter(function(k){return state[k].price===null;});var parts=[];if(orders.length){var op=orders.map(function(k){var s=state[k];if(s.qty===1) return "one "+k;var pl=k.match(/[sxz]$/i)||k.match(/(sh|ch)$/i)?k:k+"s";return numToWords(s.qty)+" "+(s.qty>1?pl:k);});if(op.length===1) parts.push("I want to order "+op[0]);else parts.push("I want to order "+op.slice(0,-1).join(", ")+" and "+op[op.length-1]);}if(asks.length){var ap=asks.map(function(k){var s=state[k];if(s.qty===1) return "one "+k;var pl=k.match(/[sxz]$/i)||k.match(/(sh|ch)$/i)?k:k+"s";return numToWords(s.qty)+" "+(s.qty>1?pl:k);});if(ap.length===1) parts.push("I would like the price for "+ap[0]);else parts.push("I would like the price for "+ap.slice(0,-1).join(", ")+" and "+ap[ap.length-1]);}return parts.join(". ")+".";}',
  'function showConfirm(){var ob=document.getElementById("overlayBody");ob.textContent=PLATFORM==="telegram"?"Head back to the chat \u2014 your message was sent!":"Head back to WhatsApp \u2014 your message was sent!";document.getElementById("overlay").className="overlay visible";document.getElementById("overlay").onclick=function(){this.className="overlay";};}',
  'document.getElementById("btnSend").addEventListener("click",function(){',
  '  var keys=Object.keys(state);if(!keys.length)return;',
  '  var btn=this;btn.disabled=true;btn.textContent="Sending...";',
  '  var items=keys.map(function(k){var s=state[k];return{product:k,quantity:s.qty,price:s.price,priceLabel:s.priceLabel,askPrice:s.price===null};});',
  '  var msg=buildMsg();',
  '  if(CHAT_ID && PLATFORM==="telegram"){',
  '    fetch(ENDPOINT,{',
  '      method:"POST",',
  '      headers:{"Content-Type":"application/json"},',
  '      body:JSON.stringify({store_token:STORE_TOKEN,biz_id:BIZ_ID,platform:PLATFORM,chat_id:CHAT_ID,items:items,message:msg})',
  '    }).then(function(r){',
  '      if(!r.ok){',
  '        return r.text().then(function(t){',
  '          btn.disabled=false;btn.textContent="Send to chat \u2192";',
  '          alert("Error "+r.status+" from table_5:\\n"+t.substring(0,300));',
  '        });',
  '      }',
  '      showConfirm();',
  '    }).catch(function(e){',
  '      btn.disabled=false;btn.textContent="Send to chat \u2192";',
  '      alert("Network error:\\n"+(e&&e.message?e.message:String(e)));',
  '    });',
  '  } else {',
  '    var enc=encodeURIComponent(msg);',
  '    var url=PLATFORM==="whatsapp"?"[URL]"+WA_NUMBER+"?text="+enc:"[URL]"+BOT_USERNAME+"?start=store_enquiry";',
  '    window.open(url,"_blank");',
  '    showConfirm();',
  '  }',
  '});',
].join('\n');

const html = '<!DOCTYPE html>'
+ '<html lang="en">'
+ '<head>'
+ '<meta charset="UTF-8"/>'
+ '<meta name="viewport" content="width=device-width,initial-scale=1.0"/>'
+ '<title>' + bizName + '</title>'
+ '<style>'
+ ':root{--accent:#F13A01;--accent-dark:#C42D00;--accent-pale:#FFF5F2;--text:#1C1917;--text-muted:#6B6560;--border:#E8E5E2;--bg:#F5F4F2;--surface:#fff;--radius:14px;--tray-h:72px;}'
+ '@media(prefers-color-scheme:dark){:root{--text:#F0EDE8;--text-muted:#9C9189;--border:#2E2926;--bg:#141210;--surface:#1E1B18;--accent-pale:rgba(241,58,1,.08);}}'
+ '*{box-sizing:border-box;margin:0;padding:0;}'
+ 'body{font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;background:var(--bg);color:var(--text);min-height:100vh;padding-bottom:calc(var(--tray-h) + 24px);}'
+ '.header{background:var(--surface);border-bottom:1px solid var(--border);padding:14px 16px;display:flex;align-items:center;gap:12px;position:sticky;top:0;z-index:100;}'
+ '.header-info h1{font-size:16px;font-weight:700;line-height:1.2;}'
+ '.header-info p{font-size:11px;color:var(--text-muted);margin-top:2px;}'
+ '.grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(156px,1fr));gap:12px;padding:16px 14px;}'
+ '.card{background:var(--surface);border:1.5px solid var(--border);border-radius:var(--radius);overflow:hidden;display:flex;flex-direction:column;transition:border-color .15s;}'
+ '.card.selected{border-color:var(--accent);}'
+ '.card-img{width:100%;aspect-ratio:1;overflow:hidden;background:var(--bg);display:flex;align-items:center;justify-content:center;}'
+ '.card-img img{width:100%;height:100%;object-fit:cover;display:block;}'
+ '.img-ph{font-size:32px;}'
+ '.card-body{padding:10px 10px 12px;display:flex;flex-direction:column;gap:6px;flex:1;}'
+ '.card-name{font-size:13px;font-weight:600;line-height:1.3;}'
+ '.price{font-size:14px;font-weight:700;color:var(--accent);}'
+ '.price-unknown{font-size:12px;color:var(--text-muted);font-style:italic;}'
+ '.badge-oos{font-size:11px;font-weight:600;background:#FEF2F2;color:#DC2626;padding:2px 8px;border-radius:20px;display:inline-block;}'
+ '.btn-select{display:flex;align-items:center;justify-content:center;width:100%;padding:9px 10px;border-radius:10px;font-size:13px;font-weight:700;border:1.5px solid var(--border);background:var(--surface);color:var(--text);cursor:pointer;transition:all .15s;margin-top:auto;}'
+ '.btn-select:hover{border-color:var(--accent);color:var(--accent);}'
+ '.btn-select.active{background:var(--accent);border-color:var(--accent);color:#fff;}'
+ '.qty-row{display:none;align-items:center;justify-content:space-between;padding:6px 0 0;}'
+ '.qty-row.visible{display:flex;}'
+ '.qty-btn{width:28px;height:28px;border-radius:50%;border:1.5px solid var(--border);background:var(--surface);font-size:16px;cursor:pointer;display:flex;align-items:center;justify-content:center;color:var(--text);transition:all .15s;flex-shrink:0;}'
+ '.qty-btn:hover{border-color:var(--accent);color:var(--accent);}'
+ '.qty-val{font-size:15px;font-weight:700;min-width:24px;text-align:center;}'
+ '.empty{text-align:center;padding:60px 20px;color:var(--text-muted);}'
+ '.tray{position:fixed;bottom:0;left:0;right:0;background:var(--surface);border-top:1px solid var(--border);padding:12px 16px;display:flex;align-items:center;gap:12px;z-index:200;height:var(--tray-h);transform:translateY(100%);transition:transform .25s ease;}'
+ '.tray.visible{transform:translateY(0);}'
+ '.tray-info{flex:1;min-width:0;}'
+ '.tray-label{font-size:11px;color:var(--text-muted);margin-bottom:2px;}'
+ '.tray-summary{font-size:13px;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;}'
+ '.btn-send{background:var(--accent);color:#fff;border:none;border-radius:12px;padding:0 20px;height:48px;font-size:14px;font-weight:700;cursor:pointer;white-space:nowrap;flex-shrink:0;transition:background .15s;}'
+ '.btn-send:hover{background:var(--accent-dark);}'
+ '.btn-send:disabled{opacity:.5;cursor:not-allowed;}'
+ '.overlay{position:fixed;inset:0;background:rgba(0,0,0,.45);display:flex;align-items:center;justify-content:center;z-index:300;opacity:0;pointer-events:none;transition:opacity .2s;}'
+ '.overlay.visible{opacity:1;pointer-events:all;}'
+ '.overlay-card{background:var(--surface);border-radius:20px;padding:32px 24px;text-align:center;max-width:320px;width:90%;}'
+ '.overlay-icon{font-size:40px;margin-bottom:12px;}'
+ '.overlay-title{font-size:18px;font-weight:700;margin-bottom:8px;}'
+ '.overlay-body{font-size:14px;color:var(--text-muted);line-height:1.6;}'
+ '.powered{text-align:center;padding:20px 16px 8px;font-size:11px;color:var(--text-muted);}'
+ '@media(max-width:380px){.grid{grid-template-columns:repeat(2,1fr);gap:10px;padding:12px;}}'
+ '</style>'
+ '</head>'
+ '<body>'
+ '<div class="header">'
+ '<div class="header-info"><h1>' + bizName + '</h1>' + descSnippet + '</div>'
+ '</div>'
+ '<div class="grid">' + cardsHtml + '</div>'
+ '<div class="powered">Powered by MySquad</div>'
+ '<div class="tray" id="tray">'
+ '<div class="tray-info">'
+ '<div class="tray-label">' + trayLabel + '</div>'
+ '<div class="tray-summary" id="traySummary"></div>'
+ '</div>'
+ '<button class="btn-send" id="btnSend" disabled>' + sendLabel + ' &rarr;</button>'
+ '</div>'
+ '<div class="overlay" id="overlay">'
+ '<div class="overlay-card">'
+ '<div class="overlay-icon">&#10004;&#65039;</div>'
+ '<div class="overlay-title">Sent!</div>'
+ '<div class="overlay-body" id="overlayBody">Head back to the chat for your response.</div>'
+ '</div></div>'
+ '<script>' + scriptLines + '</script>'
+ '</body></html>';

return [{ json: { html } }];
